		if data then
			hadMap[refId] = data
			table.insert(playEffList,data)
		end
	end
	return playEffList]]
	--- 统一由 modelSkill 接管，方便外面调用，修改
	return gModelSkill:ParsePlayEff(hadMap,playEffListStr,skinId,needCheckSound,self._skinSkillType)
end

