---技能效果计算参数
function LSkillData:InitSkillCalcData()
	local effectRefId = self._skillEffId

	local effectType = 1
	local targetNum  = 1
	local atkNum = 1
	local skillRateList

	local skillEffectRef = effectRefId and self:GetSkillEffectRef(effectRefId) or nil
	if skillEffectRef then
		local strBaseValue2 = skillEffectRef.baseValue2

		effectType = skillEffectRef.effectType
		targetNum  = skillEffectRef.targetHeroNum
		atkNum = skillEffectRef.baseValue1
		skillRateList = {}
		local arrStr = string.split(strBaseValue2,",") or {}
		for k,v in ipairs(arrStr) do
			table.insert(skillRateList,v)
		end
	else
		effectType = 1
		targetNum  = 1
		atkNum = 1
		skillRateList = {1}
	end

	self._skillCalcData  = {
		effectType = effectType,
		targetNum  = targetNum,
		atkNum = atkNum,
		skillRateList = skillRateList,
	}
end


function LSkillData:IsSameSkillGroup()
	local skillExpressList = gModelSkill:GetExpressionList(self._skillRefId)
	return gModelSkill:IsSameSkillGroup(skillExpressList)
